import{o as t,c as e,b as d}from"./vue-75de9efb.js";const i={class:"markdown-body"},o=[d('<h1 id="%E5%AE%89%E8%A3%85" tabindex="-1">安装</h1><h2 id="%E7%8E%AF%E5%A2%83%E6%94%AF%E6%8C%81" tabindex="-1">环境支持</h2><p>css做过前缀兼容，对不同浏览器支持度都挺高，js就没有专门去下那些Polyfill了。具体没有测试过，主流浏览器应该都是能用的，如果遇到问题，请自行添加 Polyfill。<br> 由于 Vue 3 不再支持 IE11，所以这个vue3开发的ui框架也不再支持 IE 浏览器。</p><table><thead><tr><th></th><th></th><th></th><th></th></tr></thead><tbody><tr><td>Edge ≥ 79</td><td>Firefox ≥ 78</td><td>Chrome ≥ 64</td><td>Safari ≥ 12</td></tr></tbody></table><h2 id="%E7%89%88%E6%9C%AC" tabindex="-1">版本</h2><p>目前还处于快速开发迭代中。</p><h2 id="%E7%9B%B4%E6%8E%A5%E4%B8%8B%E8%BD%BD%E4%BD%BF%E7%94%A8" tabindex="-1">直接下载使用</h2><p>项目跟目录下的 <code>BiLuoUI</code> 文件夹就是打包生成的插件,可以直接copy到项目中使用。 <a href="https://gitee.com/biluo_x/biluo-ui/tree/develop">项目仓库</a></p><h2 id="%E4%BD%BF%E7%94%A8%E5%8C%85%E7%AE%A1%E7%90%86%E5%99%A8" tabindex="-1">使用包管理器</h2><pre><code># 选择一个你喜欢的包管理器\n\n# NPM\n$ npm install biluo-ui --save\n\n# Yarn\n$ yarn add biluo-ui\n\n# pnpm\n$ pnpm install biluo-ui\n</code></pre>',10)],a={setup:(d,{expose:a})=>(a({frontmatter:{}}),(d,a)=>(t(),e("div",i,o)))};export{a as default};
